'use strict'
const fs = require('node:fs')
const path = require('node:path')

const EXAMPLES_DIR = path.join(__dirname, '..', 'examples')

// Entry -> bundle output. Each entry's relative requires (./lib/X, ./X) are
// resolved recursively; lib modules are emitted as IIFEs whose exports are
// destructured into top-level consts so the entry can reference them.
const TARGETS = [
  { entry: 'cycloidal_drive.jscad', out: 'cycloidal_drive_bundled.jscad' },
  { entry: 'gyroid.jscad',          out: 'gyroid_bundled.jscad' },
  { entry: 'vase.jscad',            out: 'vase_bundled.jscad' },
  { entry: 'voronoi_panel.jscad',   out: 'voronoi_panel_bundled.jscad' },
  { entry: 'thread.jscad',          out: 'thread_bundled.jscad' },
  { entry: 'gear_pair.jscad',       out: 'gear_pair_bundled.jscad' },
  { entry: 'snap_box.jscad',        out: 'snap_box_bundled.jscad' },
  { entry: 'caliper.jscad',         out: 'caliper_bundled.jscad' },
  { entry: 'heatsink.jscad',        out: 'heatsink_bundled.jscad' },
  { entry: 'water_tower.jscad',     out: 'water_tower_bundled.jscad' },
  { entry: 'truss_bridge.jscad',    out: 'truss_bridge_bundled.jscad' },
  { entry: 'lithophane.jscad',      out: 'lithophane_bundled.jscad' }
]

const RELATIVE_REQUIRE = /const\s+\{([^}]*)\}\s*=\s*require\(['"](\.\/[^'"]+)['"]\)\s*;?\s*\n/g
const EXPORTS_LINE = /^module\.exports\s*=\s*\{([^}]*)\}\s*;?\s*$/m

const stripStrictPragma = (src) => src.replace(/^['"]use strict['"];?\s*\n/m, '')

const extractExports = (src) => {
  const m = src.match(EXPORTS_LINE)
  if (!m) throw new Error('bundle-examples: no module.exports object found')
  const names = m[1]
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean)
    .map((s) => s.split(':')[0].trim())
  const body = src.replace(EXPORTS_LINE, '')
  return { names, body }
}

const stripRelativeRequires = (src) => src.replace(RELATIVE_REQUIRE, '')

// Resolve a `./foo` require against the requiring file's directory, with
// JSCAD/Node-style extension fallback (.js).
const resolveRel = (fromFile, spec) => {
  const baseDir = path.dirname(fromFile)
  const candidates = [
    path.join(baseDir, spec),
    path.join(baseDir, spec + '.js')
  ]
  for (const c of candidates) {
    if (fs.existsSync(c) && fs.statSync(c).isFile()) return c
  }
  throw new Error(`bundle-examples: cannot resolve '${spec}' from ${fromFile}`)
}

// Walk relative requires starting from entry, return absolute paths of all
// transitively required lib files in dependency-first order (so a file is
// emitted after the files it requires).
const collectLibs = (entryAbs) => {
  const ordered = []
  const seen = new Set()
  const visit = (fileAbs) => {
    if (seen.has(fileAbs)) return
    seen.add(fileAbs)
    const src = fs.readFileSync(fileAbs, 'utf8')
    // Reset stateful regex.
    RELATIVE_REQUIRE.lastIndex = 0
    let m
    while ((m = RELATIVE_REQUIRE.exec(src)) !== null) {
      const dep = resolveRel(fileAbs, m[2])
      visit(dep)
    }
    if (fileAbs !== entryAbs) ordered.push(fileAbs)
  }
  visit(entryAbs)
  return ordered
}

const wrapLib = (libAbs) => {
  const raw = fs.readFileSync(libAbs, 'utf8')
  const noStrict = stripStrictPragma(raw)
  const noRel = stripRelativeRequires(noStrict)
  const { names, body } = extractExports(noRel)
  const returnObj = `{ ${names.join(', ')} }`
  const header = `// --- inlined from examples/${path.relative(EXAMPLES_DIR, libAbs)} ---`
  return `${header}\nconst ${returnObj} = (() => {\n${body}\nreturn ${returnObj}\n})()\n`
}

const bundleEntry = (entryRel) => {
  const entryAbs = path.join(EXAMPLES_DIR, entryRel)
  const libs = collectLibs(entryAbs)
  const wrappedLibs = libs.map(wrapLib)

  const entryRaw = fs.readFileSync(entryAbs, 'utf8')
  const entrySrc = stripRelativeRequires(stripStrictPragma(entryRaw))

  const header = `'use strict'
// AUTOGENERATED by scripts/bundle-examples.js -- do not edit by hand.
// Single-file bundle of examples/${entryRel} (+ its lib/* helpers) for
// use with openjscad.xyz, which fetches one URL and cannot resolve
// relative requires. Canonical readable source:
// https://github.com/caliperhq/jscad-mcp-example/tree/main/examples
`
  return [header, ...wrappedLibs, entrySrc].join('\n')
}

const writeBundled = () => {
  for (const { entry, out } of TARGETS) {
    const outAbs = path.join(EXAMPLES_DIR, out)
    fs.writeFileSync(outAbs, bundleEntry(entry))
    console.log(`Wrote ${outAbs}`)
  }
}

if (require.main === module) writeBundled()

module.exports = { bundleEntry, writeBundled }
